import {MatchType} from "../javaTypes";
import {useLocalStorageState} from "first-common/utils";
import {T206Timeout, TimeoutReference} from "ftc-common/javaTypes";
import {isG301Timeout, isT206DependencyTimeout, isT206Timeout} from "ftc-common/timeoutUtils";
import {useInterval, useTimer} from "ftc-common/hooks";
import {getActiveStartTimer, timeString} from "./TimingTab";
import {t} from "ftc-common/i18n";
import {renderTime} from "ftc-common/utils";
import {CSSProperties, useEffect, useState} from "react";
import {delayStr} from "../util";
import {DragDropProvider} from "@dnd-kit/react";
import {move} from '@dnd-kit/helpers';
import {useSortable} from "@dnd-kit/react/sortable";

export default function MultiDivisionTimingTab({divisionTimeoutData, divisionNames, nowCallback, isHr} : {
    divisionTimeoutData: Record<number, any>,
    divisionNames: string[],
    nowCallback: () => number,
    isHr: boolean
}) {
    const [currentTime, setCurrentTime] = useState(nowCallback());
    const time = timeString(currentTime);
    const [divisionSortOrder, setDivisionSortOrder] = useLocalStorageState<number[]>(`divisionSortOrder-${window.eventCode}`, [])
    useEffect(() => {
        const initialSortOrder = Object.keys(divisionTimeoutData).map(x => parseInt(x)).sort((a,b) => a - b)
        const toAdd: number[] = []
        initialSortOrder.forEach(k => {
            if(!divisionSortOrder.includes(k)) {
                toAdd.push(k)
            }
        })
        if(toAdd.length > 0) {
            setDivisionSortOrder((prev) => [...prev, ...toAdd])
        }
    }, [divisionTimeoutData, divisionSortOrder])

    const divs = divisionSortOrder.map(o => [o, divisionTimeoutData[o]]).filter(x => !!x[1]);
    useInterval(() => {
        setCurrentTime(nowCallback());
    }, 200);
    return <div className="tab-pane fade show hrTiming" role="tabpanel">
        <div className={"text-center mt-2 mb-2"} style={{marginTop: '-1ch', marginBottom: '.5ch'}}>{t`Current time: ${time}`}</div>
        <DragDropProvider
            onDragEnd={(event) => {
                setDivisionSortOrder((items) => move(items, event));
            }}
        >
            <div className={"d-flex flex-wrap align-items-stretch"}>
                {divs.map((x, index) => <DivisionTimingInfo key={x[0]} index={index} div={x[0]} data={x[1]} divisionNames={divisionNames} nowCallback={nowCallback} isHr={isHr} currentTime={currentTime}></DivisionTimingInfo>)}
            </div>
        </DragDropProvider>
    </div>
}

function DivisionTimingInfo({index, div, data, divisionNames, nowCallback, isHr, currentTime} : {
    index: number,
    div: number,
    data: any,
    divisionNames: string[],
    nowCallback: () => number,
    isHr: boolean,
    currentTime: number
}) {
    const { ref, handleRef } = useSortable({id: div, index: index});
    const g301Timeout = data.timeouts.filter(isG301Timeout)[0];
    const g301Timer = useTimer({
        startAt: g301Timeout?.timeoutStart ?? 0,
        duration: (g301Timeout?.timeoutDuration ?? 0) / 1000,
        nowCallback: nowCallback
    });
    const expected : TimeoutReference | undefined = data.nextMatch ? getActiveStartTimer(data.nextMatch, data.timeouts, nowCallback) : data.timeouts.find(isT206DependencyTimeout);
    const expectedStartTime = useTimer({
        startAt: expected?.timeoutStart,
        duration: (expected?.timeoutDuration ?? 0) / 1000,
        nowCallback: nowCallback
    });
    const [timeSinceStart, setTimeSinceStart] = useState(-1);

    const t206Alt = expected && isT206Timeout(expected) && (expected as T206Timeout).awaitingScorePost;
    const t206AltPlayoffs = expected && isT206DependencyTimeout(expected);
    enum WarningState {
        NOT_APPLICABLE,
        AWAITING_POST,
        AVAILABLE,
        ACTIVE,
        NO_MATCH
    }
    const nextMatch = data.nextMatch;
    const lastMatch =  data.matchList.filter((x: any) => x.start > 0).sort((a: any, b: any) => b.start - a.start)[0];

    useInterval(() => {
        setTimeSinceStart(lastMatch?.start ? Math.floor((nowCallback() - lastMatch?.start) / 1000) : -1)
    }, lastMatch?.start ? 100 : null)

    let currentTimer = null;
    let x = expectedStartTime.running || !isHr ? WarningState.NOT_APPLICABLE : WarningState.AVAILABLE;
    if (!data.nextMatch) x = WarningState.NO_MATCH;
    if (g301Timeout && isHr) x = WarningState.ACTIVE;
    if (t206Alt || t206AltPlayoffs) x = WarningState.AWAITING_POST;
    const forceStretchStyle : CSSProperties = {flexDirection: 'row', alignItems: 'center', justifyContent: 'center'};

    switch (x) {
        case WarningState.NOT_APPLICABLE:
            currentTimer = <div style={{}}>
                <div className={"font-italic"}>{isHr ? t`Minimum time before next match:` : t`Time to expected start`}</div>
                <h4>{renderTime(expectedStartTime.remaining, true)}</h4>
                {/*<small className={"font-italic font-small"} hidden={t206Alt}>Tap for Fullscreen</small>*/}
            </div>
            break;
        case WarningState.NO_MATCH:
            currentTimer = <div style={{}}>
                <div className={"font-italic"}>{t`No Match Available`}</div>
                <h4></h4>
            </div>
            break;
        case WarningState.AWAITING_POST: // awaiting score post
            currentTimer = <div style={{}}>
                <div className={"font-italic"}>{isHr ? t`Minimum time before next match:`: t`Time to expected start`}</div>
                <h4>{renderTime((expected?.timeoutDuration ?? 0) / 1000)}+</h4>
                <small className={"font-italic font-small"}>{t`Awaiting `}{expected?.description}</small>
            </div>
            break;
        case WarningState.AVAILABLE:
            currentTimer = <div className={"d-flex alert-warning"} style={forceStretchStyle}>
                <div className={"font-italic alert"} style={{marginBottom: 0}}>{t`Match start time has passed!`}</div>
                <h4></h4>
            </div>
            break;
        case WarningState.ACTIVE: currentTimer = <div className={"alert-danger"}>
            <div className={"font-italic"}>{t`2-Minute Warning Active:`}</div>
            <h4>{renderTime(g301Timer.remaining)}</h4>
            {/*<small className={"font-italic font-small"}>Tap for Fullscreen</small>*/}
        </div>
            break;
    }

    return <div style={{minWidth: '50%', border: '1px solid black', flexGrow: 1}} ref={ref}>
        <span ref={handleRef} style={{cursor: 'grab', userSelect: 'none'}} className={"float-left ml-2"}><i className={"fas fa-grip-vertical"} /></span>
        <h3 className={"text-center"}>{divisionNames ? divisionNames[div] : ""}</h3>
        <h6 className={"text-center"}>Last Match: {lastMatch?.shortName ?? ""}{timeSinceStart > 0 ? ` [${renderTime(timeSinceStart, true)} ago - ${delayStr(lastMatch?.scheduledStart, lastMatch?.start)}]` : ""}</h6>
        <h6 className={"text-center"}>Next Match: {nextMatch?.shortName ?? ""}{nextMatch?.scheduledStart ? " [" + timeString(nextMatch?.scheduledStart) + "; " + renderTime((nextMatch?.scheduledStart - currentTime)/1000 + 1, true) + "]" : ""}</h6>
        {nextMatch?.type === MatchType.ELIMS ?
            <h6 className={"text-center"} style={{marginTop: '1ch'}}>Red: A{nextMatch?.red?.seed}&nbsp;&nbsp;Blue: A{nextMatch?.blue?.seed}</h6> :
            <h6 className={"text-center"} style={{marginTop: '1ch'}} hidden={!nextMatch?.red || !nextMatch?.blue}>
                Red: {nextMatch?.red.team1?.data.number}, {nextMatch?.red.team2?.data.number} {nextMatch?.red.team3 ? <>, {nextMatch?.red.team3?.data.number}</> : null}
                &nbsp;&nbsp;&nbsp;
                Blue: {nextMatch?.blue.team1?.data.number}, {nextMatch?.blue.team2?.data.number} {nextMatch?.blue.team3 ? <>, {nextMatch?.blue.team3?.data.number}</> : null}
            </h6>}
        <div className={"text-center justify-content-around"}>
            {currentTimer}
        </div>
    </div>
}